import React from 'react';

interface HomeProps {
  navigate: (page: string) => void;
}

const navLinkStyle: React.CSSProperties = {
  color: '#000080',
  textDecoration: 'underline',
  cursor: 'pointer',
  fontSize: 16,
  fontWeight: 'bold',
  letterSpacing: 2,
  background: 'none',
  border: 'none',
  padding: '4px 10px',
  fontFamily: 'inherit',
};

const Home: React.FC<HomeProps> = ({ navigate }) => {
  return (
    <div style={{
      display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
      height: '100%', padding: 40, textAlign: 'center',
      background: 'radial-gradient(ellipse at 30% 40%, rgba(180,160,220,0.12) 0%, transparent 60%), radial-gradient(ellipse at 70% 65%, rgba(160,200,220,0.10) 0%, transparent 55%), #fafafa',
    }}>
      <h1 style={{ fontSize: 88, fontFamily: '"Playfair Display", Georgia, serif', fontWeight: 900, marginBottom: 14, lineHeight: 1, color: '#1a1a2e' }}>Raghv Bhatia</h1>
      <h2 style={{ fontSize: 26, fontWeight: 'normal', fontFamily: '"Playfair Display", Georgia, serif', color: '#444', marginBottom: 64, letterSpacing: 1 }}>Digital Experience Partner</h2>
      <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', justifyContent: 'center' }}>
        <button style={navLinkStyle} onClick={() => navigate('about')}>ABOUT</button>
        <button style={navLinkStyle} onClick={() => navigate('experience')}>EXPERIENCE</button>
        <button style={navLinkStyle} onClick={() => navigate('skills')}>SKILLS</button>
        <button style={navLinkStyle} onClick={() => navigate('certifications')}>CERTIFICATIONS</button>
        <button style={navLinkStyle} onClick={() => navigate('contact')}>CONTACT</button>
      </div>
    </div>
  );
};

export default Home;
